const citiesResponse = $('Get Target Cities').first().json;
const existingResponse = $('Get Existing AI Content').first().json;

const cities = Array.isArray(citiesResponse.body) ? citiesResponse.body : (Array.isArray(citiesResponse) ? citiesResponse : []);
const existing = Array.isArray(existingResponse.body) ? existingResponse.body : (Array.isArray(existingResponse) ? existingResponse : []);

// Build set of cities that already have AI-generated content
const existingSlugs = new Set(existing.map(p => p.slug));
const existingTitles = new Set(existing.map(p => (p.title || '').toLowerCase()));

const citiesToProcess = cities.filter(city => {
  const slug = 'lawn-care-' + city.city.toLowerCase().replace(/\s+/g, '-') + '-wi';
  const titleCheck = city.city.toLowerCase();
  if (existingSlugs.has(slug)) return false;
  for (const t of existingTitles) {
    if (t.includes(titleCheck) && t.includes('lawn care')) return false;
  }
  return true;
});

// Also collect recent blog posts for internal linking
const recentPosts = existing
  .filter(p => p.slug && p.title)
  .slice(0, 20)
  .map(p => ({ title: p.title, slug: p.slug, category: p.category }));

return [{ json: { cities: citiesToProcess, count: citiesToProcess.length, totalCities: cities.length, existingCount: existing.length, recentPosts } }];

const data = $('Find Cities Needing Content').first().json;
const cities = data.cities || [];
const recentPosts = data.recentPosts || [];
return cities.map(city => ({ json: { ...city, recentPosts } }));

const city = $input.first().json;
const cityName = city.city;
const county = city.county || 'Dane';
const state = city.state || 'WI';
const pop = city.population || '';
const distance = city.distance_from_madison_miles || 0;
const recentPosts = city.recentPosts || [];

// Build internal links section for the prompt
const blogLinksText = recentPosts.slice(0, 5).map(p => `- /blog/${p.slug} — ${p.title}`).join('\n');

// Local details map for Dane County cities
const localDetails = {
  'Madison': { neighborhoods: 'Maple Bluff, Nakoma, Shorewood Hills, Midvale Heights, Westmorland', parks: 'Vilas Park, Warner Park, Olbrich Botanical Gardens, UW Arboretum', soil: 'silt loam over glacial till with moderate clay content', quirks: 'isthmus between Lakes Mendota and Monona creates unique microclimate, heavy lake-effect moisture', zones: 'USDA Zone 5a (some sheltered areas borderline 5b)' },
  'Middleton': { neighborhoods: 'Pheasant Branch, Stonefield, Middleton Hills, Century Avenue corridor', parks: 'Pheasant Branch Conservancy, Lakeview Park, Stricker Pond', soil: 'Plano silt loam, well-drained prairie soils with good organic matter', quirks: 'National Main Street award community, newer subdivisions on former farmland with compacted subsoil', zones: 'USDA Zone 5a' },
  'Sun Prairie': { neighborhoods: 'Vandenburg Heights, Prairie View, Smith\'s Crossing, Cannery Row', parks: 'Angell Park, Sheehan Park, Wetmore Park', soil: 'Dodge silt loam, heavy glacial clay underneath requiring aeration', quirks: 'fastest-growing city in Dane County, many new-construction lawns needing establishment care', zones: 'USDA Zone 5a' },
  'Fitchburg': { neighborhoods: 'Nine Springs, Seminole Hills, Jamestown, Lacy Heights', parks: 'McGaw Park, McKee Farms Park, Nine Springs E-Way', soil: 'McHenry silt loam, moderately well-drained with limestone bedrock influence', quirks: 'mix of established 1970s neighborhoods and new development, Capital City Trail access', zones: 'USDA Zone 5a' },
  'Verona': { neighborhoods: 'Hawthorne Hills, Cathedral Point, Westridge, Sugar Creek', parks: 'Fireman\'s Park, Badger Prairie Park, Ice Age Trail access', soil: 'Griswold silt loam, rolling glacial terrain with variable drainage', quirks: 'Epic Systems campus draws young professionals, rapid subdivision growth on former dairy land', zones: 'USDA Zone 5a' },
  'Monona': { neighborhoods: 'Winnequah, Bridge-Lakeview, Maywood, Nichols', parks: 'Winnequah Park, Schluter Beach, Frost Woods', soil: 'Kidder silt loam with lake-influence moisture retention', quirks: 'lakefront community bordered by Lake Monona, smaller lots with mature shade trees', zones: 'USDA Zone 5a' },
  'Waunakee': { neighborhoods: 'Kilkenny Farms, Savannah Village, South Waunakee, Downtown Historic', parks: 'Ripp Park, Centennial Park, Village Center Park', soil: 'Plano silt loam over dolomite bedrock, excellent natural drainage', quirks: 'self-proclaimed "only Waunakee in the world," rapid growth with many new subdivisions', zones: 'USDA Zone 5a' },
