  'Stoughton': { neighborhoods: 'Viking Village, Stoughton Meadows, Kegonsa Hills, Norse Ridge', parks: 'Mandt Park, Racetrack Park, Lake Kegonsa State Park nearby', soil: 'Batavia silt loam, river bottomland soil near Yahara River', quirks: 'Norwegian heritage community, annual Syttende Mai festival, older tree-lined streets', zones: 'USDA Zone 5a' },
  'Oregon': { neighborhoods: 'Bergamont, Netherwood Knoll, Prairie Meadows, Downtown Oregon', parks: 'Jaycee Park, Fireman\'s Park, Badger State Trail access', soil: 'Plano-Ringwood silt loam, former prairie with deep topsoil', quirks: 'small-town feel south of Madison, many acreage properties needing scaled lawn programs', zones: 'USDA Zone 5a' },
  'McFarland': { neighborhoods: 'McFarland Lakes, Holscher Farms, McDivot, Exchange Street', parks: 'McDaniel Park, McFarland Lions Park, Lower Mud Lake Wildlife Area', soil: 'Elburn silt loam, lake-adjacent with high water table in spots', quirks: 'sandwiched between Lake Waubesa and farmland, compact village with active outdoor culture', zones: 'USDA Zone 5a' },
  'Cottage Grove': { neighborhoods: 'Viney Meadows, Coyle Highlands, Westlawn, Crystal Lake area', parks: 'Fireman\'s Park, Crystal Lake Beach, Taylor Prairie Preserve', soil: 'Plano silt loam transitioning to Dodge clay, variable drainage across subdivisions', quirks: 'growing bedroom community east of Madison, mix of farmette and suburban lots', zones: 'USDA Zone 5a' }
